import { Alert, Button, Result, Spin } from 'antd';

export function LoadingView({ tip = 'Loading data...' }) {
  return (
    <div className="center-box">
      <Spin size="large" tip={tip} />
    </div>
  );
}

export function ErrorView({ message = 'Something went wrong', onRetry }) {
  return (
    <Result
      status="error"
      title="Load failed"
      subTitle={message}
      extra={
        onRetry ? (
          <Alert
            type="error"
            showIcon
            message="Please try again"
            action={
              <Button type="link" onClick={onRetry}>
                Retry
              </Button>
            }
          />
        ) : null
      }
    />
  );
}
