import { ApartmentOutlined } from '@ant-design/icons';
import { Col, Row, Typography } from 'antd';
import BuildingCard from '../components/BuildingCard';
import { ErrorView, LoadingView } from '../components/StateView';
import { useBuildings } from '../services/api/hooks';

const { Paragraph, Title } = Typography;

function HomePage() {
  const { data, error, isLoading, mutate } = useBuildings();

  if (isLoading) {
    return <LoadingView tip="Loading buildings..." />;
  }

  if (error) {
    return <ErrorView message={error.message} onRetry={() => mutate()} />;
  }

  return (
    <div>
      <div className="hero-block">
        <Title style={{ marginBottom: 8 }}>
          <ApartmentOutlined /> Rental Buildings in HCM City
        </Title>
        <Paragraph>
          Explore modern apartments with transparent rent and utility costs.
        </Paragraph>
      </div>

      <Row gutter={[16, 16]}>
        {data?.map((building) => (
          <Col xs={24} sm={24} md={12} lg={8} key={building.id}>
            <BuildingCard building={building} />
          </Col>
        ))}
      </Row>
    </div>
  );
}

export default HomePage;
