import { LeftOutlined } from '@ant-design/icons';
import { Button, Card, Col, Descriptions, Row, Space, Tag, Typography } from 'antd';
import { Link, useParams } from 'react-router-dom';
import ContactButtons from '../components/ContactButtons';
import ImageGallery from '../components/ImageGallery';
import { ErrorView, LoadingView } from '../components/StateView';
import { useApartment, useBuilding } from '../services/api/hooks';

const { Paragraph, Title } = Typography;

function formatCurrency(value) {
  return `${new Intl.NumberFormat('vi-VN').format(value)} VND`;
}

function ApartmentDetailPage() {
  const { apartmentId } = useParams();
  const apartmentState = useApartment(apartmentId);
  const buildingState = useBuilding(apartmentState.data?.buildingId);

  if (apartmentState.isLoading) {
    return <LoadingView tip="Loading apartment details..." />;
  }

  if (apartmentState.error) {
    return (
      <ErrorView
        message={apartmentState.error.message}
        onRetry={() => apartmentState.mutate()}
      />
    );
  }

  const apartment = apartmentState.data;

  return (
    <Space direction="vertical" size={20} style={{ width: '100%' }}>
      <Button icon={<LeftOutlined />}>
        <Link to={`/buildings/${apartment.buildingId}`}>Back to building</Link>
      </Button>

      <ImageGallery images={apartment.images} />

      <Row gutter={[16, 16]}>
        <Col xs={24} lg={14}>
          <Space direction="vertical" size={14} style={{ width: '100%' }}>
            <Title level={2}>{apartment.title}</Title>
            <Paragraph>
              Building:{' '}
              <Link to={`/buildings/${apartment.buildingId}`}>
                {buildingState.data?.name || 'Loading building name...'}
              </Link>
            </Paragraph>
            <Space wrap>
              {apartment.amenities.map((item) => (
                <Tag key={item} color="cyan">
                  {item}
                </Tag>
              ))}
            </Space>
            <ContactButtons
              phone={apartment.contact.phone}
              zalo={apartment.contact.zalo}
            />
          </Space>
        </Col>

        <Col xs={24} lg={10}>
          <Card title="Rent and utility details" className="price-card">
            <Descriptions column={1} size="small">
              <Descriptions.Item label="Room rent">
                {formatCurrency(apartment.price.base)} / month
              </Descriptions.Item>
              <Descriptions.Item label="Electric">
                {formatCurrency(apartment.price.electric)} / kWh
              </Descriptions.Item>
              <Descriptions.Item label="Water">
                {formatCurrency(apartment.price.water)} / person
              </Descriptions.Item>
              <Descriptions.Item label="Service">
                {formatCurrency(apartment.price.service)} / month
              </Descriptions.Item>
              <Descriptions.Item label="Area">
                {apartment.area} m2
              </Descriptions.Item>
            </Descriptions>
          </Card>
        </Col>
      </Row>
    </Space>
  );
}

export default ApartmentDetailPage;
